local oldCookStrFn = ACTIONS.COOK.strfn ACTIONS.COOK.strfn = function(act, ...) local inst = act.target if inst.CanForge and inst:CanForge() then return "FORGE" elseif inst.CanScrap and inst:CanScrap() then return "SCRAP" end if oldCookStrFn then return oldCookStrFn(act, ...) end end local oldCookFn = ACTIONS.COOK.fn ACTIONS.COOK.fn = function(act, ...) local inst = act.target if inst.CanForge and inst:CanForge() and inst.PreForge then inst:PreForge() return true elseif inst.CanScrap and inst:CanScrap() and inst.Scrap then inst:Scrap() return true end if oldCookFn then return oldCookFn(act, ...) end end local function CollectSceneActions(self, doer, actions, right, ...) if not doer.components.rider or not doer.components.rider:IsRiding() then local inst = self.inst if right and inst and inst.CanForge and inst.CanScrap and (inst:CanScrap() or inst:CanForge()) then table.insert(actions, ACTIONS.COOK) end end if self.dycOldCollectSceneActions then return self.dycOldCollectSceneActions(self, doer, actions, right, ...) end end local function DYCContainer(self) self.dycOldCollectSceneActions = self.CollectSceneActions self.CollectSceneActions = CollectSceneActions end return DYCContainer 